// Binary

public int binarySearch(int[] arr, int t){

int left = 0;

int right = arr.length - 1;

int mid = left + (right - left)/ 2; // Key: right + left may be larger than the max value of int

// check the mid value and modify it by change left and right

while (left <= right){

if (arr[mid] == t){

return mid;

}else if (arr[mid] > t){

right = mid - 1;

}else{

left = mid + 1;

}

}

return -1;

}

