```Java

public void SelectionSort(int[] arr){

for(int i = 0; i < arr.length-1; i++){ // loop without starting checking from the last number

int minIndex = i; // regard first num as the min value

for(int j = i + 1; j < arr.length; j++){ // inner loop for comparing

if(arr[minIndex] > arr[j]){ // if pointer number > right one

minIndex = j; // change the pointer to the right one, and the right one will update as long as j++

}

}

if(minIndex != i){ // if minIndex has changed after comparing to j, we regard it as the min number should be modified

int temp = arr[i]; // switching

arr[i] = arr[minIndex]; // switching

arr[minIndex] = temp; // switching

}

}

}

```

```Java

public void InsertionSort(int[]arr){

for (int i = 0; i < arr.length; i++){ // loop in order

int key=arr[i]; // key num = first one

int j = i - 1; // init the left one as target to compare with

while (j >= 0 && arr[j] >= key){ // while the left one is bigger than or equals to 0 and the left one is larger than the key number

arr[j+1] = arr[j]; // replace the right number to the left

j--; // -1 to keep checking the previous one, because the j will become larger as the i becomes larger.

}

arr[j+1] = key; // if program has finished comparing the first one, it will break the loop and insert the number

}

}

